example_bad:
fn main() {
    let mut s = String::from("hello");
    let r1 = &mut s;
    let r2 = &mut s; // Error: second mutable borrow
    println!("{}, {}", r1, r2);
}

fixes.code:
let mut s = String::from("hello");
{
    let r1 = &mut s;
    r1.push_str(" world");
} // r1 goes out of scope
let r2 = &mut s; // Now this works

let mut s = String::from("hello");
let r1 = &mut s;
r1.push_str(" world"); // Last use of r1
let r2 = &mut s; // Works because r1 is no longer used
println!("{}", r2);
